import Rating from "@mui/material/Rating";
import Button from "@mui/material/Button";
import sp1 from "../../assets/images/sp1.png";
import { TfiFullscreen } from "react-icons/tfi";
import { IoMdHeartEmpty } from "react-icons/io";
import ProducModal from "../ProductModal";
import { useContext, useState } from "react";
import { MyContext } from "../../App";

const ProducItem = () => {
  const context = useContext(MyContext);
  const viewProductDetails = (id) => {
    context.setisOpenProductModal(true);
  };
  const closeProductModal = () => {
    context.setisOpenProductModal(false);
  };

  return (
    <>
      <div className="item productItem">
        <div className="imgWrapper">
          <img src={sp1} className="w-100" />
          <span className="badge bg-primary"> 30%</span>
          <div className="actions">
            <Button onClick={() => viewProductDetails(1)}>
              <TfiFullscreen />
            </Button>
            <Button>
              <IoMdHeartEmpty style={{ fontSize: "20px" }} />
            </Button>
          </div>
        </div>
        <div className="info">
          <h4> MLB - Áo thun unisex cổ tròn tay ngắn hiện đại</h4>
          <span className="text-success d-block"> Sẵn hàng</span>
          <Rating
            className="mt-2 mb-2"
            name="read-only"
            value={5}
            readOnly
            size="small"
            precision={0.1}
          />
          <div className="d-flex">
            <span className="oldPrice"> 499.000 VNĐ</span>
            <span className="newPrice text-danger ml-3"> 299.000 VNĐ</span>
          </div>
        </div>
      </div>
    </>
  );
};

export default ProducItem;
